  "evaluation_of_each_diagnosis": {
    "Sarcoidosis": {
      "supporting_facts": "Bilateral hilar lymphadenopathy, arthralgia (ankles/wrists), pulmonary nodules, and constitutional symptoms (fever, fatigue) are classic.",
      "against_facts": "The rapid progression from normal imaging 4.5 months ago to extensive mediastinal lymphadenopathy and pulmonary nodules is aggressive for typical sarcoidosis.",
      "support_level": "Well-supported"
