      "supporting_facts": "B-symptoms (fever, fatigue), rapid onset of mediastinal/hilar adenopathy, and multiple pulmonary nodules.",
      "against_facts": "Lack of peripheral lymphadenopathy or splenomegaly on exam.",
      "support_level": "Well-supported"
    },
    "Tuberculosis": {
      "supporting_facts": "Bilateral hilar adenopathy, fever, constitutional symptoms, nodules.",
      "against_facts": "Absence of respiratory symptoms (cough, sputum), travel history not high-risk, normal white-cell count.",
      "support_level": "Weakly supported"
    },
    "Bartonellosis": {
      "supporting_facts": "Cat scratch exposure (6 months prior), fever, arthralgia, cutaneous ecchymoses/macules.",
      "against_facts": "Mediastinal adenopathy of this extent is less common; typically regional lymphadenopathy is seen.",
      "support_level": "Weakly supported"
    },
