      "supporting_facts": "Common cause of hilar lymphadenopathy and pulmonary nodules in specific geographies.",
      "against_facts": "No clear exposure history (spelunking, etc.) provided; symptoms have a slightly different tempo.",
      "support_level": "Weakly supported"
    },
    "Systemic Lupus Erythematosus": {
      "supporting_facts": "Arthritis, fever, constitutional symptoms.",
      "against_facts": "Normal urinalysis (no renal involvement), no cytopenias, lack of classic rash.",
      "support_level": "Weakly supported"
    },
    "Vasculitis": {
      "supporting_facts": "Systemic symptoms, skin findings (ecchymosis/erythema), arthralgia.",
      "against_facts": "Mediastinal lymphadenopathy is not a characteristic feature of most primary systemic vasculitides.",
      "support_level": "Weakly supported"
    }
